<?php require __DIR__.'/../includes/bootstrap.php';require_auth();$id=(int)($_GET['id']??0);$s=db()->prepare('SELECT * FROM brands WHERE id=?');$s->execute([$id]);$b=$s->fetch();if(!$b){http_response_code(404);exit('Brand not found.');}if(!can_manage_brand($b)){http_response_code(403);exit('Access denied.');}$error='';if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();try{$name=trim($_POST['name']??'');if($name==='')throw new RuntimeException('Brand name is required.');$logo=save_uploaded_image('logo','brands/logos',$id);$banner=save_uploaded_image('banner','brands/banners',$id);$sql='UPDATE brands SET name=?,category=?,short_description=?,description=?,website=?,public_email=?,founded_year=?'.($logo?',logo_path=?':'').($banner?',banner_path=?':'').' WHERE id=?';$args=[$name,trim($_POST['category']??''),trim($_POST['short_description']??''),trim($_POST['description']??''),trim($_POST['website']??''),trim($_POST['public_email']??''),((int)($_POST['founded_year']??0))?:null];if($logo)$args[]=$logo;if($banner)$args[]=$banner;$args[]=$id;db()->prepare($sql)->execute($args);flash('success','Brand updated.');redirect('dashboard.php?id='.$id);}catch(Throwable $e){$error=$e->getMessage();}}app_header('Edit Brand');?><section class="dashboard-hero"><h1>Edit <?=e($b['name'])?></h1></section><?php if($error):?><div class="alert error"><?=e($error)?></div><?php endif?><form method="post" enctype="multipart/form-data" class="profile-form"><?=csrf_field()?><section class="app-card form-grid"><label>Brand name<input name="name" value="<?=e($b['name'])?>" required></label><label>Category<input name="category" value="<?=e($b['category'])?>"></label><label class="full">Short description<input name="short_description" value="<?=e($b['short_description'])?>"></label><label class="full">Description<textarea name="description"><?=e($b['description'])?></textarea></label><label>Website<input name="website" value="<?=e($b['website'])?>"></label><label>Public email<input name="public_email" value="<?=e($b['public_email'])?>"></label><label>Founded year<input type="number" name="founded_year" value="<?=e((string)$b['founded_year'])?>"></label><label>Replace logo<input type="file" name="logo" accept="image/*"></label><label>Replace banner<input type="file" name="banner" accept="image/*"></label></section><div class="form-actions"><a class="button ghost" href="dashboard.php?id=<?=$id?>">Cancel</a><button class="button primary">Save Brand</button></div></form><?php app_footer();
